var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"어때? 관리국에서 운영하는 무료 급식소야.","JPN":"どう？　管理局で運営してる炊き出しだよ。","ENG":"What do you say? It’s a free soup kitchen run by the Administration.","TWN":"怎麼樣？這裡是由管理局經營的免費飯館。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"이런 곳도 있었네.","JPN":"こんなところもあったんだね。","ENG":"I didn’t know such a place existed.","TWN":"竟然有這種地方。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"훗. 물론 이런 고급 정보를 누구나 다 아는 건 아니지. 나 만나서 행운인 줄 알아.","JPN":"ふっ。もちろんこんな高級情報を誰でも知ってるわけじゃないんだ。私に出会えて幸運だと思いなよ。","ENG":"Hmph! You’re lucky to have met me. Who else would give you such valuable information?","TWN":"呵，這麼高級的地方可不是誰都知道的，遇見我算你幸運！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아. 줄 빠졌다. 빨리 안 가면 아저씨들한테 다 뺏긴다.","JPN":"あ。列が減った。早く行かないと、おじさんたちに全部取られちゃう。","ENG":"Hey look, the lines moving. If we don’t get there fast, everyone else is gonna take all the food.","TWN":"欸，我們脫隊了，趕快跟上，否則大叔們會把菜都搶光的。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"SPEAR_MAID_DREAM_FAKE","text":{"KOREA":"톰! 새치기하는 거 다 봤어. 맨밥만 주기 전에 얌전히 뒤로 가.","JPN":"トム！　割り込んだの見てたよ。大人しく後ろに行かないとおかずあげないから。","ENG":"Tom! I saw you cutting in line! Go to the back of the line or I’m only gonna give you rice!","TWN":"湯姆！我有看到你插隊，乖乖回去排隊，否則別怪我只給你白飯！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TOM_NPC_DREAM_NULL","text":{"KOREA":"쳇. 하여간 예리하다니까. 한 번을 안 넘어가.","JPN":"チッ。まったく、鋭いぜ。一度も大目に見てくれねえ。","ENG":"Tch! Her and her keen eye... How does she catch me every time?","TWN":"嘖，眼睛這麼利，每次都逃不過你的法眼！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPEAR_MAID_DREAM_FAKE","text":{"KOREA":"너처럼 티 팍팍 내면서 새치기하는 인간도 드물거든?","JPN":"あんたのように一目で割り込みってわかるやつもそうそういないよ？","ENG":"Well, not everyone cuts in line as blatantly as you!","TWN":"像你插隊插得這麼明顯的人也算少見啦？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPEAR_MAID_DREAM_FAKE","text":{"KOREA":"말 잘 들으면 <color=#ffd34c>특별 수제 소스</color> 따로 퍼 줄게. 이번에 만든 회심의 역작이야.","JPN":"言うことよく聞いたら、<color=#ffd34c>特製手作りソース</color>をあげる。今回作った会心の力作なんだ。","ENG":"Behave, and I’ll give you more of my <color=#ffd34c>special sauce</color>. It’s my greatest batch yet!","TWN":"你聽話的話，我就另外裝一些<color=#ffd34c>特製醬料</color>給你，這次的成果很讚喔！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TOM_NPC_DREAM_NULL","text":{"KOREA":"어…… 나 다시 새치기하면 안 될까?","JPN":"え……俺また割り込んじゃダメかな？","ENG":"Uh... C-can I just cut back in line instead?","TWN":"那個……我選擇插隊可以嗎？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그렇게 깨작깨작 먹다간 저기 빨간 머리 봉사자님한테 등짝 맞을지도 모른다?","JPN":"そうやってしぶしぶ食べてると、あっちの赤髪のボランティアさんに叩かれるかもしれないよ？","ENG":"You keep eating like that and that red-haired volunteer’s gonna give you an earful!","TWN":"你這樣挑食的話，等下那個紅髮姊姊會打人喔！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"딱 봐도 손이 엄청 매워 보이는데.","JPN":"パッと見、叩かれたらめっちゃ痛そう。","ENG":"Just look at her. Doesn’t she look like she’ll spit fire?","TWN":"看也知道她的手勁應該很厲害吧？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"……으응.","JPN":"……うん。","ENG":"…Okay.","TWN":"……嗯嗯。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"오늘따라 씹히는 게 적긴 하네. 치사하게 소시지도 두 개씩 밖에 안 주고.","JPN":"今日は具が少ないなぁ。ソーセージも二つずつしかくれないなんて、ケチくさい。","ENG":"I guess today’s menu isn’t that great. Plus she only gave me two sausages.","TWN":"今天的東西好少，連小香腸都只給二根，真是小氣！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"내 거 먹을래?","JPN":"私のも食べる？","ENG":"Do you want mine?","TWN":"你要吃我的嗎？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……소시지?","JPN":"……ソーセージ？","ENG":"Your sausages?","TWN":"……你說小香腸？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"으응. 별로 입맛이 없어서.","JPN":"うん。あんまり食欲なくて。","ENG":"Yes... I’m not that hungry.","TWN":"嗯嗯，我吃不太下。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"소시지를 준다고? 두 개밖에 없는 걸?","JPN":"ソーセージくれるの？　二つしかないのに？","ENG":"You’re giving me your sausages? But you only have two?","TWN":"你要把小香腸給我？一人只有二根欸？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"글린다가 다 먹어도 좋아.","JPN":"グリンダが全部食べてもいいよ。","ENG":"You can have all if you want, Glinda.","TWN":"都給你吃吧。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};